  const cmdsDir = path.join(dir, 'commands');
  const skillsDir = path.join(dir, 'skills');

  if (fs.existsSync(agentsDir)) totalAgents += fs.readdirSync(agentsDir).filter(f => f.endsWith('.md')).length;
  if (fs.existsSync(cmdsDir)) totalCommands += fs.readdirSync(cmdsDir).filter(f => f.endsWith('.md')).length;
  if (fs.existsSync(skillsDir)) totalSkills += fs.readdirSync(skillsDir).filter(f => f.endsWith('.md')).length;

  if (!fs.existsSync(agentsDir) && !fs.existsSync(cmdsDir) && !fs.existsSync(skillsDir)) {
    errors.push(name + ' (empty plugin)');
  }
});

console.log('=== Wshobson Plugins Content ===');
console.log('Plugins:', dirs.length);
console.log('Agent definitions (.md):', totalAgents);
console.log('Command definitions (.md):', totalCommands);
console.log('Skill definitions (.md):', totalSkills);
if (errors.length) console.log('Empty plugins:', errors.join(', '));
else console.log('No empty plugins - all valid!');
